class Solution:
    def canSortArray(self, nums: list) -> bool:
        from itertools import groupby
        groups = [list(g) for _, g in groupby(nums, key=lambda x: bin(x).count('1'))]
        prev_max = float('-inf')
        for g in groups:
            gmin, gmax = min(g), max(g)
            if gmin < prev_max:
                return False
            prev_max = gmax
        return True

