var canSortArray = function(nums) {
    const popcount = x => { let c = 0; while (x) { c += x & 1; x >>= 1; } return c; };
    const n = nums.length;
    let prevMax = 0, i = 0;
    while (i < n) {
        let j = i;
        const pc = popcount(nums[i]);
        while (j < n && popcount(nums[j]) === pc) j++;
        let segMin = Infinity, segMax = -Infinity;
        for (let t = i; t < j; t++) { segMin = Math.min(segMin, nums[t]); segMax = Math.max(segMax, nums[t]); }
        if (segMin < prevMax) return false;
        prevMax = segMax;
        i = j;
    }
    return true;
};
